class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def is_sorted(self):
        if self.head is None or self.head.next is None:
            return True

        current = self.head
        while current.next is not None:
            if current.data > current.next.data:
                return False
            current = current.next
        return True
